滑块验证码实现 思路：
随机数生成x，y两个随机数；x，y随机数大小不能超过背景图片的大小，不能小于遮盖图片的大小 uuid生成bgId作为最后背景图的标识 把x，y作为最大坐标值，x，y分别减去遮盖图片的大小作为最小坐标值，通过最大和最小坐标值可以得到一个矩形 在背景图片中裁剪出这个矩形大小的图片，这个图片为滑块图片 把背景图中裁剪的区域填充进遮盖图片，填充后的图片为真正的背景图 分别把滑块图片和背景图进行base64编码 把背景图的bgid以及x轴坐标保存在服务器缓存中，把bgid保存在客户端缓存中 返回给前端滑块图片和背景图片的base64编码以及y轴坐标 用户滑动滑块后前端返回用户滑动后的x轴坐标 后端拿到客户端缓存中的bgId以及前端返回的x轴坐标把这些数据和服务器缓存中的数据做对比，在允许的误差内即为验证通过 用到的第三方库为：
&#34;github.com/disintegration/imaging&#34; &#34;github.com/google/uuid&#34; func GetRandInt(max int) int { num, _ := rand.Int(rand.Reader, big.NewInt(int64(max-1))) return int(num.Int64()) } func CreateCode() (string, string, int, int) { //生成随机数,用来随机选取图片 nums := GetRandInt(10) //用于生成的图片名称 imageId := uuid.New().String() //获取图片 f, _ := os.Open(&#34;./jigsaw/bg/&#34; + strconv.Itoa(nums) + &#34;.png&#34;) //获取随机x坐标 imageRandX := GetRandInt(480 - 100) if imageRandX &lt; 200 { imageRandX += 200 } //获取随机y坐标 imageRandY := GetRandInt(240 - 100) if imageRandY &lt; 100 { imageRandY += 100 } //转化为image对象 m, err := png.Decode(f) if err != nil { panic(err) } //设置截取的最大坐标值和最小坐标值 maxPotion := image.Point{ X: imageRandX, Y: imageRandY, } minPotion := image.Point{ X: imageRandX - 100, Y: imageRandY - 100, } subimg := image.Rectangle{ Max: maxPotion, Min: minPotion, } f, err = os.Create(&#34;./jigsaw/code/&#34; + imageId + &#34;screenshot.jpeg&#34;) defer f.Close() //截取图像 data := imaging.Crop(m, subimg) jpeg.Encode(f, data, nil) //base64编码 buffer := bytes.NewBuffer(nil) jpeg.Encode(buffer, data, nil) maskBase64 := base64.StdEncoding.EncodeToString(buffer.Bytes()) //设置遮罩 bkBase64 := createCodeImg(&#34;./jigsaw/bg/&#34;+strconv.Itoa(nums)+&#34;.png&#34;, minPotion, imageId) return maskBase64, bkBase64, imageRandX, imageRandY } func createCodeImg(path string, minPotion image.Point, imageId string) string { bg, err := os.Open(path) if err != nil { panic(err) } maskFile, err := os.Open(&#34;./jigsaw/mask.png&#34;) if err != nil { panic(err) } bgimg, err := png.Decode(bg) maskimg, err := png.Decode(maskFile) //参数：背景图，遮盖图，坐标，透明度 data := imaging.Overlay(bgimg, maskimg, minPotion, 1.0) f, err := os.Create(&#34;./jigsaw/code/&#34; + imageId + &#34;.jpeg&#34;) defer f.Close() jpeg.Encode(f, data, nil) //base64编码 buffer := bytes.NewBuffer(nil) jpeg.Encode(buffer, data, nil) return base64.StdEncoding.EncodeToString(buffer.Bytes()) }

SpringBoot 整合 rabbitMQ mac安装brew install rabbitmq
application.yml设置 spring: rabbitmq: host: 47.115.50.193 username: admin password: admin 创建交换机，消息队列，并进行绑定 @Configuration public class RabbitMQConfig { private static final String TOPIC_NAME = &#34;top_name&#34;; private static final String QUEUE_NAME = &#34;queue_name&#34;; //交换机 @Bean(&#34;queueEx&#34;) public Exchange queueEx(){ return ExchangeBuilder.topicExchange(TOPIC_NAME).durable(true).build(); } //消息队列 @Bean(&#34;queue&#34;) public Queue queue(){ return QueueBuilder.durable(QUEUE_NAME).build(); } //绑定 @Bean public Binding queueExchange(@Qualifier(&#34;queueEx&#34;) Exchange exchange,@Qualifier(&#34;queue&#34;) Queue queue){ return BindingBuilder.bind(queue).to(exchange).with(&#34;a.#&#34;).noargs(); } } @Autowired private RabbitTemplate rabbitTemplate; 生产者 public void q(){ rabbitTemplate.convertAndSend(&#34;top_name&#34;,&#34;a.qwe&#34;,&#34;rabbitmqboot&#34;); } 消费者 @RabbitListener(queues = &#34;queue_name&#34;) //设置要监听的消息队列 public void listenerq(Message message,Channel channel){ System.out.println(new String(message.getBody())); } 消息可靠投递 Application.yml配置 rabbitmq: publisher-confirm-type: correlated Java代码配置 package com.xiaoyu.config; import org.springframework.amqp.core.ReturnedMessage; import org.springframework.amqp.rabbit.connection.CorrelationData; import org.springframework.amqp.rabbit.core.RabbitTemplate; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.stereotype.Component; import javax.annotation.PostConstruct; @Component public class PubConfirmAndReturn implements RabbitTemplate.ReturnsCallback,RabbitTemplate.ConfirmCallback{ @Autowired RabbitTemplate rabbitTemplate; @PostConstruct public void init(){ rabbitTemplate.setReturnsCallback(this); rabbitTemplate.setConfirmCallback(this); } //confirm确定模式 @Override public void confirm(CorrelationData correlationData, boolean b, String s) { if (b) { System.out.println(&#34;消息发送到exchange成功&#34;); } else { System.out.println(&#34;失败原因：&#34;+ s); } } //return退回模式 @Override public void returnedMessage(ReturnedMessage returnedMessage) { System.out.println(&#34;消息送exchange到queue失败，详情为：&#34;); System.out.println(&#34;消息主体 message : &#34;+new String(returnedMessage.getMessage().getBody())); System.out.println(&#34;描述：&#34;+ returnedMessage.toString()); System.out.println(&#34;消息使用的交换器 exchange : &#34;+ returnedMessage.getExchange()); System.out.println(&#34;消息使用的路由键 routing : &#34;+ returnedMessage.getRoutingKey()); } } rabbitmq 整个消息投递的路径为： producer—&gt;rabbitmq broker—&gt;exchange—&gt;queue—&gt;consumer 消息从 producer 到 exchange 则会返回一个 confirmCallback 确认模式。 消息从 exchange–&gt;queue 投递失败则会返回一个 returnCallback退回模式 。
ack @RabbitListener(queues = &#34;queue_name&#34;) public void listener(Message message, Channel channel){ long deliveryTag = message.getMessageProperties().getDeliveryTag(); try { System.out.println(new String(message.getBody())); System.out.println(&#34;处理业务逻辑&#34;); Thread.sleep(2000); int a = 1/0; // 手动签收 channel.basicAck(deliveryTag,true); } catch (Exception e) { // 第三个参数：requeue：重回队列，如果设置为true，则消息重新回到queue，broker会重新发送消息给消费端 try { channel.basicNack(deliveryTag,true,true); } catch (Exception ioException) { ioException.printStackTrace(); } } } 当消息在被消费时，如果在不手动签收则会停滞，如果在处理业务逻辑时出错，则可以设置是否重回队列 ttl过期 队列过期 @Bean(&#34;queuettl&#34;) public Queue queueTTL(){ // ttl:队列的过期时间 return QueueBuilder.durable(&#34;queue_ttl&#34;).ttl(1000000).build(); } @Bean(&#34;exchangettl&#34;) public Exchange exchangeTTL(){ return ExchangeBuilder.topicExchange(&#34;exchange_ttl&#34;).durable(true).build(); } @Bean public Binding ttl(@Qualifier(&#34;queuettl&#34;) Queue queue,@Qualifier(&#34;exchangettl&#34;) Exchange exchange){ return BindingBuilder.bind(queue).to(exchange).with(&#34;q.#&#34;).noargs(); } 队列过期是指：所有发送到这个队列的消息如果没有在规定的时间消费就会被处理掉（删除改消息） 消息过期 public void ttl(){ // 消息后处理对象，设置一些消息的参数信息 MessagePostProcessor messagePostProcessor = new MessagePostProcessor() { @Override public Message postProcessMessage(Message message) throws AmqpException { // 设置message的信息 message.getMessageProperties().setExpiration(&#34;10000&#34;); // 返回该消息 return message; } }; // 如果同时设置了队列过期时间和消息单独过期时间，以时间短的为准。如下列情况是到十秒同时过期 // 队列过期会将队列内的消息全部移除 // 消息过期后，只有消息在队列的顶端才会判断其是否过期，过期则移除 // 队列过期 rabbitTemplate.convertAndSend(&#34;exchange_ttl&#34;,&#34;q.aa&#34;,&#34;ttl&#34;); // 消息单独过期 rabbitTemplate.convertAndSend(&#34;exchange_ttl&#34;,&#34;q.aa&#34;,&#34;ttl&#34;,messagePostProcessor); } 消息过期是指：发送的这一条消息会被设置过期时间，正常发送的消息则不会过期。 dlx死信 造成死信的原因： 过期时间
//.ttl(10000) public void one_dlx(){ rabbitTemplate.convertAndSend(&#34;test_exchange_dlx&#34;,&#34;test_dlx.xx&#34;,&#34;one_del....&#34;); } 长度限制
//.maxLength(10)	设置最大为10条消息 public void two_dlx(){ for (int i = 0; i &lt; 20; i++) { rabbitTemplate.convertAndSend(&#34;test_exchange_dlx&#34;,&#34;test_dlx.xx&#34;,&#34;two_del....&#34;); } } 消息拒收
public void three_dlx(Message message, Channel channel){ System.out.println(new String(message.getBody())); try { channel.basicNack(message.getMessageProperties().getDeliveryTag(),true,false); } catch (IOException e) { e.printStackTrace(); } } 死信配置 // 1:声明正常队列和交换机进行绑定 @Bean(&#34;test_queue_dlx&#34;) public Queue test_queue_dlx(){ return QueueBuilder.durable(&#34;test_queue_dlx&#34;).deadLetterExchange(&#34;exchange_dlx&#34;).deadLetterRoutingKey(&#34;dlx.suibian&#34;).ttl(10000).maxLength(10).build(); } @Bean(&#34;test_exchange_dlx&#34;) public Exchange test_exchange_dlx(){ return ExchangeBuilder.topicExchange(&#34;test_exchange_dlx&#34;).durable(true).build(); } @Bean public Binding test_binding_dlx(@Qualifier(&#34;test_queue_dlx&#34;)Queue queue,@Qualifier(&#34;test_exchange_dlx&#34;)Exchange exchange){ return BindingBuilder.bind(queue).to(exchange).with(&#34;test_dlx.#&#34;).noargs(); } // 2.声明死信队列和交换机进行绑定 @Bean(&#34;queue_dlx&#34;) public Queue queue_dlx(){ return QueueBuilder.durable(&#34;queue_dlx&#34;).build(); } @Bean(&#34;exchange_dlx&#34;) public Exchange exchange_dlx(){ return ExchangeBuilder.topicExchange(&#34;exchange_dlx&#34;).durable(true).build(); } @Bean public Binding binding_dlx(@Qualifier(&#34;queue_dlx&#34;)Queue queue,@Qualifier(&#34;exchange_dlx&#34;)Exchange exchange){ return BindingBuilder.bind(queue).to(exchange).with(&#34;dlx.#&#34;).noargs(); } 死信队列可以理解为是被绑定正常队列的回收站，死信队列和正常队列一样，一样可以消费其中的消息 ttl+dlx延迟队列 配置 @Bean(&#34;test_queue_ttl_dlx&#34;) public Queue test_queue_ttl_dlx(){ return QueueBuilder.durable(&#34;test_queue_ttl_dlx&#34;).deadLetterExchange(&#34;exchange_ttl_dlx&#34;).deadLetterRoutingKey(&#34;ttl_dlx.suibian&#34;).ttl(10000).build(); } @Bean(&#34;test_exchange_ttl_dlx&#34;) public Exchange test_exchange_ttl_dlx(){ return ExchangeBuilder.topicExchange(&#34;test_exchange_ttl_dlx&#34;).durable(true).build(); } @Bean public Binding test_binding_ttl_dlx(@Qualifier(&#34;test_queue_ttl_dlx&#34;)Queue queue,@Qualifier(&#34;test_exchange_ttl_dlx&#34;)Exchange exchange){ return BindingBuilder.bind(queue).to(exchange).with(&#34;test_ttl_dlx.#&#34;).noargs(); } @Bean(&#34;queue_ttl_dlx&#34;) public Queue queue_ttl_ttl_dlx(){ return QueueBuilder.durable(&#34;queue_ttl_dlx&#34;).build(); } @Bean(&#34;exchange_ttl_dlx&#34;) public Exchange exchange_ttl_dlx(){ return ExchangeBuilder.topicExchange(&#34;exchange_ttl_dlx&#34;).durable(true).build(); } @Bean public Binding binding_ttl_dlx(@Qualifier(&#34;queue_ttl_dlx&#34;)Queue queue,@Qualifier(&#34;exchange_ttl_dlx&#34;)Exchange exchange){ return BindingBuilder.bind(queue).to(exchange).with(&#34;ttl_dlx.#&#34;).noargs(); } 生产者 @GetMapping(&#34;/ttl_dlx&#34;) @ResponseBody public void ttl_dlx(){ for (int i = 0; i &lt; 10; i++) { rabbitTemplate.convertAndSend(&#34;test_exchange_ttl_dlx&#34;,&#34;test_ttl_dlx.xx&#34;,&#34;ttl_dlx...&#34;); } } 消费者 @RabbitListener(queues = &#34;queue_ttl_dlx&#34;) public void ttl_dlx_li(Message message,Channel channel){ System.out.println(new String(message.getBody())); try { channel.basicAck(message.getMessageProperties().getDeliveryTag(),true); } catch (IOException e) { e.printStackTrace(); } } 延迟队列：设置队列为过期队列，当改消息过期后到绑定的死信队列里面，从而实现消息的延迟

基本框架搭建： 创建UserRealm.java 继承AuthorizingRealm 实现AuthorizationInfo()：授权方法。 实现AuthenticationInfo()：认证方法。 创建ShiroConfig.java配置类 @bean加载UserRealm()：加载UserRealm.java到Spring。 @bean加载DefaultWebSecurityManager()：shiro管理器。 @bean加载ShiroFilterFactoryBean()：shiro过滤器。 根据需要可加载的方法： ShiroDialect()：用来整合shiro thymeleaf。 HashedCredentialsMatcher()：设置加密。 EhCacheManager()：缓存。 DefaultWebSessionManager()：设置session管理器。 UserRealm.java具体方法实现 授权方法： @Override protected AuthorizationInfo doGetAuthorizationInfo(PrincipalCollection principalCollection) { SimpleAuthorizationInfo info = new SimpleAuthorizationInfo(); Subject subject = SecurityUtils.getSubject(); Users users = (Users)subject.getPrincipal(); info.addStringPermission(users.getPerms()); return info; } SimpleAuthorizationInfo info = new SimpleAuthorizationInfo();授权方法。 Subject subject = SecurityUtils.getSubject();获取subject。 Users users = (Users)subject.getPrincipal();通过subject获取到当前用户。 users是由AuthenticationInfo()认证方法的SimpleAuthenticationInfo通过参数传入。 info.addStringPermission(users.getPerms());根据用户权限添加权限。 return info即可 认证方法： @Autowired UserServiceImpl userService; @Override protected AuthenticationInfo doGetAuthenticationInfo(AuthenticationToken token) throws AuthenticationException { UsernamePasswordToken upToken = (UsernamePasswordToken) token; Users users = userService.queryUserByName(upToken.getUsername()); if (users == null) { return null; } Subject subject = SecurityUtils.getSubject(); Session session = subject.getSession(); session.setAttribute(&#34;loginuser&#34;,users); //ByteSource.Util.bytes(users.getSalt()):告诉shiro加盐的盐值 if (users.getSalt() != null){//必须判断是否有盐值不然会报错：null return new SimpleAuthenticationInfo(users,users.getPassword(),ByteSource.Util.bytes(users.getSalt()),&#34;&#34;); } return new SimpleAuthenticationInfo(users,users.getPassword(),&#34;&#34;); } UsernamePasswordToken upToken = (UsernamePasswordToken) token;获取账号密码令牌 @autoWired属性注入UserServiceImpl Users users = userService.queryUserByName(upToken.getUsername())； upToken.getUsername()：获取当前用户名称。 userService.queryUserByName：查询该用户，并返回。 判断users是否为空，如果为空返回null。shiro会自动报错：没有用户错误。 Subject subject = SecurityUtils.getSubject();获取subject。 Session session = subject.getSession();获取session。 session.setAttribute(&ldquo;loginuser&rdquo;,users);把用户信息传入session方便后边使用。 users.getSalt() != null;判断该用户是否有加盐。 不等于null代表加盐，需要返回盐值。 return new SimpleAuthenticationInfo(users,users.getPassword(),ByteSource.Util.bytes(users.getSalt()),&quot;&quot;); 第一个参数为传递该用户的信息 第二个参数：users.getPassword()：传入密码由shiro来判断密码是否正确。 第三个参数：ByteSource.Util.bytes(users.getSalt())：传入盐值 第四个参数：当前的realm名称 等于null代表没有加盐，不需要返回盐值。 return new SimpleAuthenticationInfo(users,users.getPassword(),&quot;&quot;); Controller.java @RequestMapping(&#34;/login&#34;) public ModelAndView log(String username,String password,boolean rememberme){ ModelAndView modelAndView = new ModelAndView(); //获取当前用户 Subject subject = SecurityUtils.getSubject(); //封装用户的登录数据 UsernamePasswordToken token = new UsernamePasswordToken(username, password); try { subject.login(token);//执行登录方法，如果没有异常就ok token.setRememberMe(rememberme); modelAndView.setViewName(&#34;/index&#34;); } catch (UnknownAccountException e) {//用户名不存在异常 modelAndView.addObject(&#34;msgUP&#34;,&#34;用户名不存在或者错误&#34;); modelAndView.setViewName(&#34;/login&#34;); System.out.println(e); } catch (IncorrectCredentialsException e) {//密码不存在 modelAndView.addObject(&#34;msgUP&#34;,&#34;密码不存在&#34;); modelAndView.setViewName(&#34;/login&#34;); System.out.println(e); } return modelAndView; } 登录过程 登录页面填写账号密码. 传入到对应的映射方法. 方法调用subject.login(token)进行登录. 跳转到认证方法方法进行账号密码判断. 判断之后返回到映射方法. 映射方法根据返回结果进行对应逻辑. ShiroConfig.java配置类 UserRealm()：UserRealm方法 @Bean public UserRealm userRealm(@Qualifier(&#34;hashedCredentialsMatcher&#34;)HashedCredentialsMatcher hashedCredentialsMatcher) { UserRealm userRealm = new UserRealm(); userRealm.setCredentialsMatcher(hashedCredentialsMatcher);//添加密码设置。 return userRealm; } 该方法的主要作用就是把UserRealm.java类加载到Spring容器 DefaultWebSecurityManager()：shiro安全管理器方法 @Bean() public DefaultWebSecurityManager getDefaultWebSecurityManager( @Qualifier(&#34;userRealm&#34;) UserRealm userRealm, @Qualifier(&#34;ehCacheManager&#34;)EhCacheManager ehCacheManager, @Qualifier(&#34;defaultWebSessionManager&#34;)DefaultWebSessionManager defaultWebSessionManager, @Qualifier(&#34;cookieRememberMeManager&#34;)CookieRememberMeManager meManager) { DefaultWebSecurityManager securityManager = new DefaultWebSecurityManager(); //关联userRealm securityManager.setRealm(userRealm); //添加第三方缓存 securityManager.setCacheManager(ehCacheManager); //添加设置的sessionManager securityManager.setSessionManager(defaultWebSessionManager); //添加cookie管理器 securityManager.setRememberMeManager(meManager); return securityManager; } 该方法作用为： 添加关联userRealm 添加第三方缓存管理器 添加自定义设置的session管理器 ShiroFilterFactoryBean()：shiro权限过滤器方法 @Bean public ShiroFilterFactoryBean shiroFilterFactoryBean(@Qualifier(&#34;getDefaultWebSecurityManager&#34;) DefaultWebSecurityManager defa) { ShiroFilterFactoryBean bean = new ShiroFilterFactoryBean(); //设置安全管理器 bean.setSecurityManager(defa); //添加shiro的内置过滤器 /* shiro已经定义的关键字 anon:无需认证就可以访问 authc：必须认证才能访问 user：必须拥有记住我功能才能访问 perms：拥有对某个资源的权限才能访问 logout:退出当前登录 */ //设置访问拦截 LinkedHashMap&lt;String, String&gt; hashMap = new LinkedHashMap&lt;&gt;(); //授权 hashMap.put(&#34;/user/add&#34;,&#34;perms[user:add]&#34;); hashMap.put(&#34;/user/update&#34;,&#34;perms[user:update]&#34;); //授权要在认证前边 hashMap.put(&#34;/user/*&#34;, &#34;authc&#34;); //退出登录,/logout不需要具体的映射方法，只要跳转到这个路径就退出。 hashMap.put(&#34;/logout&#34;,&#34;logout&#34;); bean.setFilterChainDefinitionMap(hashMap); //设置登录页面 bean.setLoginUrl(&#34;/toLogin&#34;); //设置未授权请求 bean.setUnauthorizedUrl(&#34;/unauthorized&#34;); bean.setSuccessUrl(&#34;/toLogin&#34;); return bean; } 安全管理器需要添加到该bean： bean.setSecurityManager(defa); 授权map集合的key为资源，value为访问这些资源要携带的权限字符串。 退出登录的路径只需要和前端的退出按钮上的路径一样即可，不需要具体的映射实现方法。 未授权请求就是当该用户没有该权限时访问该资源就会跳转到这个路径的前端页面上，这个需要映射方法的实现来进行跳转 授权和认证的区别： 认证就是必须要登录账号才可以访问 授权时必须要用户登录并携带该权限才可以访问 ShiroDialect()：用来整合shiro thymeleaf方法 @Bean public ShiroDialect shiroDialect(){ return new ShiroDialect(); } &lt;h1&gt;首页&lt;/h1&gt; &lt;!-- th:if=&#34;${session.loginuser!=null}&#34;判断是否有这个session值--&gt; &lt;h2 th:if=&#34;${session.loginuser!=null}&#34;&gt;&lt;a href=&#34;/logout&#34;&gt;退出&lt;/a&gt;&lt;/h2&gt; &lt;h2 th:if=&#34;${session.loginuser==null}&#34;&gt;&lt;a href=&#34;/toLogin&#34;&gt;登录&lt;/a&gt;&lt;/h2&gt; &lt;p th:text=&#34;${msg}&#34;&gt;&lt;/p&gt; &lt;!-- shiro:hasPermission=&#34;user:add&#34;检查是否有这个权限--&gt; &lt;div shiro:hasPermission=&#34;user:add&#34;&gt; &lt;a th:href=&#34;@{/user/add}&#34;&gt;add&lt;/a&gt; &lt;/div&gt; &lt;div shiro:hasPermission=&#34;user:update&#34;&gt; &lt;a th:href=&#34;@{/user/update}&#34;&gt;update&lt;/a&gt; &lt;/div&gt; &lt;!-- thymeleaf和shiro的名称空间--&gt; xmlns:th=&#34;http://www.thymeleaf.org&#34; xmlns:shiro=&#34;http://www.pollix.at/thymeleaf/shiro&#34; &lt;!-- pom.xml坐标 --&gt; &lt;dependency&gt; &lt;groupId&gt;com.github.theborakompanioni&lt;/groupId&gt; &lt;artifactId&gt;thymeleaf-extras-shiro&lt;/artifactId&gt; &lt;version&gt;2.0.0&lt;/version&gt; &lt;/dependency&gt; HashedCredentialsMatcher()：设置加密方法 @Bean(name = &#34;hashedCredentialsMatcher&#34;) public HashedCredentialsMatcher shiro(){ HashedCredentialsMatcher credentialsMatcher = new HashedCredentialsMatcher(); //加密方式 credentialsMatcher.setHashAlgorithmName(&#34;md5&#34;); //散列次数，次数整个项目要统一不然会报错 credentialsMatcher.setHashIterations(1); return credentialsMatcher; } @RequestMapping(&#34;/adduser&#34;) @ResponseBody public String md5(String username,String password){ //在注册是对密码进行加密 Md5Hash md5Hash = new Md5Hash(password); //加盐加密 int num = new Random().nextInt(90000)+10000; Md5Hash md5Hash1 = new Md5Hash(password, num+&#34;&#34;); //加盐加密加散列 val md5Hash2 = new Md5Hash(password, num + &#34;&#34;, 3); //第二种方法进行加密,和Md5Hash一样是重载形式的 final SimpleHash md5 = new SimpleHash(&#34;md5&#34;, password, num + &#34;&#34;, 3); return &#34;只加密&#34;+md5Hash.toString()+&#34;&lt;br&gt;&#34; +&#34;加盐加密：&#34;+md5Hash1.toString()+&#34;盐值：&#34;+num+&#34;&lt;br&gt;&#34; +&#34;加盐加密加散列&#34;+md5Hash2.toString()+&#34;盐值：&#34;+num+&#34;&lt;br&gt;&#34; +&#34;SimpleHash加密&#34;+md5.toString()+&#34;盐值：&#34;+num; } 这两个的散列次数要一致。 散列不一定要随机数字，也可以是字符串，或者用户名称，或者自定义。 shiro默认的加盐是加在密码前边，这个可以自定义实现。 加盐必须是字符串形式不然会报错。 EhCacheManager()：缓存方法 @Bean public EhCacheManager ehCacheManager(){ EhCacheManager ehCacheManager = new EhCacheManager(); ehCacheManager.setCacheManagerConfigFile(&#34;classpath:ehcache.xml&#34;); return ehCacheManager; } &lt;dependency&gt; &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt; &lt;artifactId&gt;spring-boot-starter-cache&lt;/artifactId&gt; &lt;/dependency&gt; &lt;dependency&gt; &lt;groupId&gt;net.sf.ehcache&lt;/groupId&gt; &lt;artifactId&gt;ehcache&lt;/artifactId&gt; &lt;/dependency&gt; &lt;dependency&gt; &lt;groupId&gt;org.apache.shiro&lt;/groupId&gt; &lt;artifactId&gt;shiro-ehcache&lt;/artifactId&gt; &lt;version&gt;1.7.1&lt;/version&gt; &lt;/dependency&gt; &lt;?xml version=&#34;1.0&#34; encoding=&#34;utf-8&#34; ?&gt; &lt;ehcache updateCheck=&#34;false&#34; dynamicConfig=&#34;false&#34;&gt; &lt;diskStore path=&#34;&#34;/&gt; &lt;cache name=&#34;user&#34; maxEntriesLocalHeap=&#34;1000&#34;/&gt; &lt;defaultCache name=&#34;defaultCache&#34; maxElementsInMemory=&#34;1000&#34; maxElementsOnDisk=&#34;10000000&#34; eternal=&#34;false&#34; overflowToDisk=&#34;false&#34; diskPersistent=&#34;false&#34; timeToIdleSeconds=&#34;120&#34; timeToLiveSeconds=&#34;120&#34; diskExpiryThreadIntervalSeconds=&#34;120&#34; memoryStoreEvictionPolicy=&#34;LRU&#34; /&gt; &lt;/ehcache&gt; 第一步导入坐标。
第二步在applcation.yml同级目录创建ehcache.xml
第三步@bean
DefaultWebSessionManager()：设置session管理器方法 @Bean public DefaultWebSessionManager defaultWebSessionManager(){ final DefaultWebSessionManager sessionManager = new DefaultWebSessionManager(); //设置session过期时间为10秒，单位是毫秒 sessionManager.setGlobalSessionTimeout(30*1000); return sessionManager; } shiro默认的session是半个小时过期，这里可以自定义过期时间。
CookieRememberMeManager()：设置记住我功能 添加cookie
@Bean public CookieRememberMeManager cookieRememberMeManager(){ final CookieRememberMeManager cookieRememberMeManager = new CookieRememberMeManager(); final SimpleCookie simpleCookie = new SimpleCookie(&#34;rememberme&#34;); //cookie存活时间，单位秒 simpleCookie.setMaxAge(30*24*60*60); return cookieRememberMeManager; } 其他 jdbc和mybatis配置
