@Bean public DefaultWebSecurityManager securityManager(){ final DefaultWebSecurityManager securityManager = new DefaultWebSecurityManager(); securityManager.setAuthenticator(authenticator()); final ArrayList&lt;Realm&gt; realms = new ArrayList&lt;&gt;(); realms.add(userRealm()); realms.add(mangerRealm()); securityManager.setRealms(realms); return securityManager; } 多个realm是通过集合进行添加。其余操作不变。
分支 进行判断选择其中的一个或几个realm来进行执行
第一步：自定义token 继承UsernamePasswordToken,增强其方法，添加一个logintype参数。 package com.example.shiroConfig; import org.apache.shiro.authc.UsernamePasswordToken; public class MyToken extends UsernamePasswordToken { private String loginType; public MyToken(String username,String password,String loginType) { super(username,password); this.loginType = loginType; } public String getLoginType() { return loginType; } public void setLoginType(String loginType) { this.loginType = loginType; } } 第二步：自定义认证器 继承ModularRealmAuthenticator,重写AuthenticationInfo方法，在方法中进行判断选择要使用的realm。 package com.example.shiroConfig; import com.sun.org.slf4j.internal.Logger; import com.sun.org.slf4j.internal.LoggerFactory; import org.apache.shiro.authc.AuthenticationException; import org.apache.shiro.authc.AuthenticationInfo; import org.apache.shiro.authc.AuthenticationToken; import org.apache.shiro.authc.pam.ModularRealmAuthenticator; import org.apache.shiro.realm.Realm; import java.util.ArrayList; import java.util.Collection; public class MyAuthenticator extends ModularRealmAuthenticator { @Override protected AuthenticationInfo doAuthenticate(AuthenticationToken authenticationToken) throws AuthenticationException { Collection&lt;Realm&gt; realms = this.getRealms(); final MyToken token = (MyToken) authenticationToken; final ArrayList&lt;Realm&gt; myRealm = new ArrayList&lt;&gt;();//自定义一个realm集合 for (Realm realm:realms) { if (realm.getName().startsWith(token.getLoginType())) {//根据logintype来判断使用的realm，把要使用的realm添加到自定义的realm集合中。 myRealm.add(realm); } } return myRealm.size() == 1 ? this.doSingleRealmAuthentication(myRealm.iterator().next(), authenticationToken) : this.doMultiRealmAuthentication(myRealm, authenticationToken); //这里返回判断要使用自定义的realm集合。 } } 第三步：添加bean @Bean public MyAuthenticator authenticator(){ return new MyAuthenticator(); } 第四步：加入安全管理器 @Bean public DefaultWebSecurityManager securityManager(){ final DefaultWebSecurityManager securityManager = new DefaultWebSecurityManager(); securityManager.setAuthenticator(authenticator());//加入安全管理器 final ArrayList&lt;Realm&gt; realms = new ArrayList&lt;&gt;(); realms.add(userRealm()); realms.add(mangerRealm()); securityManager.setRealms(realms); return securityManager; } 第五步：前端接收的参数传递到自定义的token @RequestMapping(&#34;/login&#34;) public ModelAndView login(String username,String password,String logintype){ System.out.println(username+password+logintype); ModelAndView modelAndView = new ModelAndView(); //获取当前用户 Subject subject = SecurityUtils.getSubject(); //封装用户的登录数据 final MyToken token = new MyToken(username, password, logintype);//自定义的token try { subject.login(token); modelAndView.setViewName(&#34;/index&#34;); } catch (Exception e) { modelAndView.setViewName(&#34;/login&#34;); } return modelAndView; }

