一：使用 1.引入依赖 &lt;!-- https://mvnrepository.com/artifact/javax.mail/mail --&gt; &lt;dependency&gt; &lt;groupId&gt;javax.mail&lt;/groupId&gt; &lt;artifactId&gt;mail&lt;/artifactId&gt; &lt;version&gt;1.4.7&lt;/version&gt; &lt;/dependency&gt; &lt;!-- https://mvnrepository.com/artifact/javax.activation/activation --&gt; &lt;dependency&gt; &lt;groupId&gt;javax.activation&lt;/groupId&gt; &lt;artifactId&gt;activation&lt;/artifactId&gt; &lt;version&gt;1.1.1&lt;/version&gt; &lt;/dependency&gt; 2.简单邮件 package com.xiaoyu; import com.sun.mail.util.MailSSLSocketFactory; import javax.mail.*; import javax.mail.internet.InternetAddress; import javax.mail.internet.MimeMessage; import java.security.GeneralSecurityException; import java.util.Properties; public class ProSimpl { public static void main(String[] args) throws GeneralSecurityException, MessagingException { final Properties properties = new Properties(); properties.setProperty(&#34;mail.host&#34;,&#34;smtp.qq.com&#34;); properties.setProperty(&#34;mail.transport.protocol&#34;,&#34;smtp&#34;); properties.setProperty(&#34;mail.smtp.auth&#34;,&#34;true&#34;); // qq邮箱还需要设置ssl加密，qq独有的其他邮箱没有 final MailSSLSocketFactory mailSSLSocketFactory = new MailSSLSocketFactory(); mailSSLSocketFactory.setTrustAllHosts(true); properties.put(&#34;mail.smtp.ssl.enable&#34;,&#34;true&#34;); properties.put(&#34;mail.smtp.ssl.socketFactory&#34;,mailSSLSocketFactory); // 1.创建定义整个应用程序所需的环境信息的session对象 // qq独有的其他邮箱没有 final Session session = Session.getDefaultInstance(properties, new Authenticator() { @Override protected PasswordAuthentication getPasswordAuthentication() { // 发件人邮箱用户名，授权码/ return new PasswordAuthentication(&#34;xxxx@qq.com&#34;, &#34;xxxxx&#34;); } }); // 1.开启debug模式 session.setDebug(true); // 2.通过session得到transport对象 final Transport transport = session.getTransport(); // 3.使用邮箱的用户名和授权码连接邮箱服务器 transport.connect(&#34;smtp.qq.com&#34;,&#34;xxxx@qq.com&#34;,&#34;xxxx&#34;); // 4.创建邮件 final MimeMessage message = new MimeMessage(session); // 指明发件人 message.setFrom(new InternetAddress(&#34;xxxx@qq.com&#34;)); // 指明收件人 message.setRecipients(Message.RecipientType.TO, String.valueOf(new InternetAddress(&#34;xxxx@qq.com&#34;))); // 邮件标题 message.setSubject(&#34;hello&#34;); // 邮件内容 message.setContent(&#34;&lt;h1 style=&#39;color:red&#39;&gt;hello world&lt;/h1&gt;&#34;,&#34;text/html;charset=utf-8&#34;); // 5.发送邮件 transport.sendMessage(message,message.getAllRecipients()); // 6.关闭 transport.close(); } } 3.图片邮件 package com.xiaoyu; import com.sun.mail.util.MailSSLSocketFactory; import javax.activation.DataHandler; import javax.activation.FileDataSource; import javax.mail.*; import javax.mail.internet.InternetAddress; import javax.mail.internet.MimeBodyPart; import javax.mail.internet.MimeMessage; import javax.mail.internet.MimeMultipart; import java.security.GeneralSecurityException; import java.util.Properties; public class ProImage { public static void main(String[] args) throws GeneralSecurityException, MessagingException { final Properties properties = new Properties(); properties.setProperty(&#34;mail.host&#34;,&#34;smtp.qq.com&#34;); properties.setProperty(&#34;mail.transport.protocol&#34;,&#34;smtp&#34;); properties.setProperty(&#34;mail.smtp.auth&#34;,&#34;true&#34;); // qq邮箱还需要设置ssl加密，qq独有的其他邮箱没有 final MailSSLSocketFactory mailSSLSocketFactory = new MailSSLSocketFactory(); mailSSLSocketFactory.setTrustAllHosts(true); properties.put(&#34;mail.smtp.ssl.enable&#34;,&#34;true&#34;); properties.put(&#34;mail.smtp.ssl.socketFactory&#34;,mailSSLSocketFactory); // 1.创建定义整个应用程序所需的环境信息的session对象 // qq独有的其他邮箱没有 final Session session = Session.getDefaultInstance(properties, new Authenticator() { @Override protected PasswordAuthentication getPasswordAuthentication() { // 发件人邮箱用户名，授权码/ return new PasswordAuthentication(&#34;xxx@qq.com&#34;, &#34;xxxx&#34;); } }); // 1.开启debug模式 session.setDebug(true); // 2.通过session得到transport对象 final Transport transport = session.getTransport(); // 3.使用邮箱的用户名和授权码连接邮箱服务器 transport.connect(&#34;smtp.qq.com&#34;,&#34;xxxx@qq.com&#34;,&#34;xxxx&#34;); // 4.创建邮件 final MimeMessage message = new MimeMessage(session); // 指明发件人 message.setFrom(new InternetAddress(&#34;xxxx@qq.com&#34;)); // 指明收件人 message.setRecipients(Message.RecipientType.TO, String.valueOf(new InternetAddress(&#34;xxxx@qq.com&#34;))); // 邮件标题 message.setSubject(&#34;hello&#34;); // 邮件内容 // 图片 MimeBodyPart image = new MimeBodyPart(); DataHandler dataHandler = new DataHandler(new FileDataSource(&#34;src/main/resources/zhizhuxia.jpg&#34;)); image.setDataHandler(dataHandler); image.setContentID(&#34;zhizhuxia.jpg&#34;); // 文字 MimeBodyPart text = new MimeBodyPart(); text.setContent(&#34;图片&lt;img src=&#39;cid:zhizhuxia.jpg&#39;&gt;&#34;,&#34;text/html;charset=utf-8&#34;); // 描述数据关系 MimeMultipart mimeMultipart = new MimeMultipart(); mimeMultipart.addBodyPart(image); mimeMultipart.addBodyPart(text); mimeMultipart.setSubType(&#34;related&#34;); // 设置到消息中，保存修改 message.setContent(mimeMultipart); message.saveChanges(); // 5.发送邮件 transport.sendMessage(message,message.getAllRecipients()); // 6.关闭 transport.close(); } } 4.附件邮件 package com.xiaoyu; import com.sun.mail.util.MailSSLSocketFactory; import javax.activation.DataHandler; import javax.activation.FileDataSource; import javax.mail.*; import javax.mail.internet.*; import java.security.GeneralSecurityException; import java.util.Properties; public class ProImageAndFile { public static void main(String[] args) throws GeneralSecurityException, MessagingException { final Properties properties = new Properties(); properties.setProperty(&#34;mail.host&#34;,&#34;smtp.qq.com&#34;); properties.setProperty(&#34;mail.transport.protocol&#34;,&#34;smtp&#34;); properties.setProperty(&#34;mail.smtp.auth&#34;,&#34;true&#34;); // qq邮箱还需要设置ssl加密，qq独有的其他邮箱没有 final MailSSLSocketFactory mailSSLSocketFactory = new MailSSLSocketFactory(); mailSSLSocketFactory.setTrustAllHosts(true); properties.put(&#34;mail.smtp.ssl.enable&#34;,&#34;true&#34;); properties.put(&#34;mail.smtp.ssl.socketFactory&#34;,mailSSLSocketFactory); // 1.创建定义整个应用程序所需的环境信息的session对象 // qq独有的其他邮箱没有 final Session session = Session.getDefaultInstance(properties, new Authenticator() { @Override protected PasswordAuthentication getPasswordAuthentication() { // 发件人邮箱用户名，授权码/ return new PasswordAuthentication(&#34;xxxxx@qq.com&#34;, &#34;xxxx&#34;); } }); // 1.开启debug模式 session.setDebug(true); // 2.通过session得到transport对象 final Transport transport = session.getTransport(); // 3.使用邮箱的用户名和授权码连接邮箱服务器 transport.connect(&#34;smtp.qq.com&#34;,&#34;xxxx@qq.com&#34;,&#34;xxxxx&#34;); // 4.邮件内容 final MimeMessage message = message(session); // 5.发送邮件 transport.sendMessage(message,message.getAllRecipients()); // 6.关闭 transport.close(); } public static MimeMessage message(Session session) throws MessagingException { final MimeMessage message = new MimeMessage(session); message.setFrom(new InternetAddress(&#34;xxxx@qq.com&#34;)); message.setRecipients(Message.RecipientType.TO,&#34;xxxx@qq.com&#34;); message.setSubject(&#34;主题&#34;); // 图片 MimeBodyPart image = new MimeBodyPart(); DataHandler dataHandler = new DataHandler(new FileDataSource(&#34;src/main/resources/zhizhuxia.jpg&#34;)); image.setDataHandler(dataHandler); image.setContentID(&#34;zhizhuxia.jpg&#34;); // 文字 MimeBodyPart text = new MimeBodyPart(); text.setContent(&#34;图片&lt;img src=&#39;cid:zhizhuxia.jpg&#39;&gt;&#34;,&#34;text/html;charset=utf-8&#34;); // 附件 MimeBodyPart file1 = new MimeBodyPart(); file1.setDataHandler(new DataHandler(new FileDataSource(&#34;src/main/resources/a.text&#34;))); file1.setFileName(&#34;a.text&#34;); MimeBodyPart file2 = new MimeBodyPart(); file2.setDataHandler(new DataHandler(new FileDataSource(&#34;src/main/resources/b.text&#34;))); file2.setFileName(&#34;b.text&#34;); // 描述数据关系 MimeMultipart mimeMultipart = new MimeMultipart(); mimeMultipart.addBodyPart(image); mimeMultipart.addBodyPart(text); mimeMultipart.setSubType(&#34;related&#34;); // 拼装正文为主体 final MimeBodyPart mimeBodyPart = new MimeBodyPart(); mimeBodyPart.setContent(mimeMultipart); // 拼接附件 final MimeMultipart allfile = new MimeMultipart(); allfile.addBodyPart(file1); allfile.addBodyPart(file2); allfile.addBodyPart(mimeBodyPart); allfile.setSubType(&#34;mixed&#34;); // 放到消息中 message.setContent(allfile); message.saveChanges(); return message; } } 二：boot整合 1.引入依赖
